JS_CODE = '// State\n    const answers = {};\n    let currentQ = 1;\n    const totalQ = 10;\n\n    function startDiagnosis() {\n      document.getElementById(\'start-screen\').classList.add(\'hidden\');\n      document.getElementById(\'quiz-screen\').classList.remove(\'hidden\');\n      updateProgress(1);\n    }\n\n    function selectOption(qNum, value, btn) {\n      answers[qNum] = value;\n      // Reset selected state\n      const parent = btn.closest(\'.question-card\');\n      parent.querySelectorAll(\'.option-btn\').forEach(b => b.classList.remove(\'selected\'));\n      btn.classList.add(\'selected\');\n\n      // Show navigation buttons\n      document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', qNum === 1);\n      if (qNum < totalQ) {\n        document.getElementById(\'next-btn\').classList.remove(\'hidden\');\n        document.getElementById(\'result-btn\').classList.add(\'hidden\');\n      } else {\n        document.getElementById(\'next-btn\').classList.add(\'hidden\');\n        document.getElementById(\'result-btn\').classList.remove(\'hidden\');\n      }\n    }\n\n    function nextQuestion() {\n      if (!answers[currentQ]) {\n        alert(\'選択肢を選んでください\');\n        return;\n      }\n      if (currentQ < totalQ) {\n        hideQuestion(currentQ);\n        currentQ++;\n        showQuestion(currentQ);\n        updateProgress(currentQ);\n        document.getElementById(\'prev-btn\').classList.remove(\'hidden\');\n        if (currentQ < totalQ) {\n          document.getElementById(\'next-btn\').classList.add(\'hidden\');\n          document.getElementById(\'result-btn\').classList.add(\'hidden\');\n        }\n        if (answers[currentQ]) {\n          selectOption(currentQ, answers[currentQ], getSelectedBtn(currentQ));\n        } else {\n          document.getElementById(\'next-btn\').classList.add(\'hidden\');\n          document.getElementById(\'result-btn\').classList.add(\'hidden\');\n        }\n        window.scrollTo({ top: 0, behavior: \'smooth\' });\n      }\n    }\n\n    function prevQuestion() {\n      if (currentQ > 1) {\n        hideQuestion(currentQ);\n        currentQ--;\n        showQuestion(currentQ);\n        updateProgress(currentQ);\n        document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', currentQ === 1);\n        document.getElementById(\'next-btn\').classList.remove(\'hidden\');\n        document.getElementById(\'result-btn\').classList.add(\'hidden\');\n        if (answers[currentQ]) {\n          const btn = getSelectedBtn(currentQ);\n          if (btn) selectOption(currentQ, answers[currentQ], btn);\n        }\n        window.scrollTo({ top: 0, behavior: \'smooth\' });\n      }\n    }\n\n    function hideQuestion(q) {\n      document.querySelector(`.question-card[data-q="${q}"]`).classList.add(\'hidden\');\n    }\n\n    function showQuestion(q) {\n      const card = document.querySelector(`.question-card[data-q="${q}"]`);\n      card.classList.remove(\'hidden\');\n      card.classList.add(\'fade-in\');\n    }\n\n    function getSelectedBtn(q) {\n      const card = document.querySelector(`.question-card[data-q="${q}"]`);\n      return card ? card.querySelector(\'.option-btn.selected\') : null;\n    }\n\n    function updateProgress(q) {\n      const pct = Math.round((q / totalQ) * 100);\n      document.getElementById(\'current-q\').textContent = q;\n      document.getElementById(\'progress-pct\').textContent = pct;\n      document.getElementById(\'progress-bar\').style.width = pct + \'%\';\n    }\n\n    function calcScores() {\n      const scores = { pairs: 0, with: 0, tapple: 0 };\n\n      // Q3: 目標\n      if (answers[3] === \'marriage\') { scores.pairs += 3; scores.with += 2; }\n      else if (answers[3] === \'casual\') { scores.tapple += 3; scores.with += 1; }\n      else if (answers[3] === \'friend\') { scores.tapple += 2; scores.with += 2; }\n\n      // Q4: 出会い方\n      if (answers[4] === \'hobby\') { scores.tapple += 3; scores.with += 1; }\n      else if (answers[4] === \'values\') { scores.with += 3; scores.pairs += 1; }\n      else if (answers[4] === \'looks\') { scores.tapple += 2; scores.pairs += 1; }\n      else if (answers[4] === \'stability\') { scores.pairs += 3; sco'
